const TAU = Math.PI * 2;

type Point = {x: number; y: number};
type RiskState = 'isolated' | 'frozen' | 'challenged' | 'monitored';

const mod = (value: number, divisor: number) =>
  ((value % divisor) + divisor) % divisor;

const cyclePulse = (frame: number, period: number, offset = 0) =>
  0.5 + 0.5 * Math.sin((mod(frame + offset, period) / period) * TAU);

const smoothRange = (
  value: number,
  input: [number, number],
  output: [number, number] = [0, 1],
) =>
  interpolate(value, input, output, {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.bezier(0.22, 1, 0.36, 1),
  });

const quadPoint = (a: Point, b: Point, c: Point, t: number): Point => {
  const u = 1 - t;
  return {
    x: u * u * a.x + 2 * u * t * b.x + t * t * c.x,
    y: u * u * a.y + 2 * u * t * b.y + t * t * c.y,
  };
};

const polygonPoints = (
  cx: number,
  cy: number,
  radius: number,
  sides: number,
  rotation = -90,
) =>
  Array.from({length: sides}, (_, i) => {
    const angle = ((rotation + (i * 360) / sides) * Math.PI) / 180;
    return `${cx + Math.cos(angle) * radius},${cy + Math.sin(angle) * radius}`;
  }).join(' ');

