const MAP_SCALE = 178.57262038666588;
const project = (lon: number, lat: number): Point => {
  const lambda = (lon * Math.PI) / 180;
  const phi = (lat * Math.PI) / 180;
  const phi2 = phi * phi;
  const phi4 = phi2 * phi2;
  const rawX =
    lambda *
    (0.8707 -
      0.131979 * phi2 +
      phi4 * (-0.013791 + phi4 * (0.003971 * phi2 - 0.001529 * phi4)));
  const rawY =
    phi *
    (1.007226 +
      phi2 *
        (0.015085 +
          phi4 * (-0.044475 + 0.028874 * phi2 - 0.005916 * phi4)));
  return {x: 560 + MAP_SCALE * rawX, y: 312 - MAP_SCALE * rawY};
};

