          <linearGradient id="wave-stroke" x1="0" y1="0" x2="1" y2="0"><stop offset="0" stopColor={C.mint} /><stop offset="0.55" stopColor={C.violet} /><stop offset="1" stopColor={C.coral} /></linearGradient>
